mapper.sql:
FROM ( SELECT employees_id, MAX(sync_date) AS sync_date FROM employee_additions
CONVERT(DATE, sync_date) BETWEEN CONVERT(DATE, #{startDate}) AND CONVERT(DATE, #{endDate})
GROUP BY employees_id ) ea_latest INNER JOIN employee_information ei ON ea_latest.employees_id = ei.id LEFT JOIN hk_erp_sync_status es ON ea_latest.employees_id = es.employee_id AND es.sync_type = 'HK_ONBOARDING'
AND ei.department_id IN
#{did}
AND ei.staff_name LIKE '%' + #{staffName} + '%'
AND ei.staff_no LIKE '%' + #{staffNo} + '%'
AND = #{syncStatus}
AND ei.staff_no NOT IN
#{sno}

FROM employee_information ei LEFT JOIN hk_erp_sync_status es ON ei.id = es.employee_id AND es.sync_type = 'HK_LEAVING'
ei.leave_date IS NOT NULL
AND ei.department_id IN
#{did}
AND CONVERT(DATE, ei.leave_date) BETWEEN CONVERT(DATE, #{startDate}) AND CONVERT(DATE, #{endDate})
AND ei.staff_name LIKE '%' + #{staffName} + '%'
AND ei.staff_no LIKE '%' + #{staffNo} + '%'
AND ISNULL(es.sync_status, 0) = #{syncStatus}
AND ei.staff_no NOT IN
#{sno}
